// n8n webhook typeVersion 1.1 wraps POST body as { body: {...}, headers: {...} }
// All request + user fields are already in the webhook payload — no DB re-query needed.
const b = $input.first().json.body;
if (!b || !b.request_id) throw new Error('Missing request_id in webhook body.');

return {
  json: {
    request_id: b.request_id,
    user_name: b.name || 'Client',
    user_email: b.email,
    origin: b.origin,
    destination: b.destination,
    cargo_type: b.cargo_type || '',
    commodity: b.commodity || 'General Merchandise',
    cargo_specification: b.cargo_specification || '',
    packing_type: b.packing_type || 'PALLETS',
    quantity: b.quantity || 1,
    weight_kg: b.weight_kg,
    incoterms: b.incoterms || 'FOB',
    container_type: b.container_type || '',
    is_hazardous: b.is_hazardous || false,
    needs_insurance: b.needs_insurance || false,
    vessel: b.vessel || '',
    special_requirements: b.special_requirements || ''
  }
};

const req = $('Code: Extract Request Data').first().json;
const cargoType = (req.cargo_type || '').toLowerCase();
const allForwarders = $input.all();
const matched = allForwarders.filter(f => {
  const specs = (f.json.specializations || '').toLowerCase();
  return specs.includes(cargoType) || specs.includes('all') || specs === '' || !f.json.specializations;
});
return matched.map(f => {
  const emailSubject = `[NEW REQUEST] ${req.request_id} — ${req.origin} → ${req.destination}`;
  const emailBody = `<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'></head><body style='margin:0;padding:0;background:#f0f4f8;font-family:-apple-system,BlinkMacSystemFont,system-ui,Arial,sans-serif;'><table width='100%' cellpadding='0' cellspacing='0' border='0' style='background:#f0f4f8;'><tr><td align='center' style='padding:32px 16px;'><table cellpadding='0' cellspacing='0' border='0' style='max-width:600px;width:100%;background:#ffffff;border-radius:10px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.09);'><tr><td style='background:#1a1a1a;padding:36px 32px 28px;text-align:center;'><table cellpadding='0' cellspacing='0' border='0' align='center' style='margin:0 auto 16px;'><tr><td style='padding:0 0 16px;line-height:0;'><img src='https://cargolink.sa/cargolink1.png' alt='CargoLink' width='160' height='64' border='0' style='display:block;width:160px;height:64px;border:0;outline:none;'></td></tr></table><h1 style='margin:0 0 3px;font-size:22px;font-weight:700;color:#ffffff;letter-spacing:-0.3px;'>New Freight Request</h1><p style='margin:0;font-size:11px;color:rgba(255,255,255,0.5);letter-spacing:0.12em;text-transform:uppercase;'>CargoLink · Freight Marketplace</p></td></tr><tr><td style='height:3px;background:#b5973a;font-size:0;line-height:0;'> </td></tr><tr><td style='padding:36px 40px;'><div style='background:#f8fafc;border:2px solid #1a1a1a;border-radius:6px;padding:14px;text-align:center;margin:0 0 20px;'><span style='font-family:monospace;font-size:22px;font-weight:900;color:#1a1a1a;'>${req.request_id}</span></div><p style='margin:0 0 8px;font-size:15px;font-weight:700;color:#111827;'>Dear ${f.json.company_name},</p><p style='margin:0 0 16px;font-size:14px;color:#4b5563;line-height:1.7;'>A new freight request matching your profile has been posted. <strong>Only the first 3 quotations are accepted.</strong></p><table cellpadding='0' cellspacing='0' border='0' style='width:100%;border-collapse:collapse;border:1px solid #e5e7eb;border-radius:8px;margin:0 0 16px;'><tr><td style='padding:8px 16px;font-size:13px;color:#6b7280;border-bottom:1px solid #e5e7eb;width:130px;'>Route</td><td style='padding:8px 16px;font-size:13px;font-weight:700;color:#111827;border-bottom:1px solid #e5e7eb;'>${req.origin} → ${req.destination}</td></tr><tr><td style='padding:8px 16px;font-size:13px;color:#6b7280;border-bottom:1px solid #e5e7eb;'>Cargo Type</td><td style='padding:8px 16px;font-size:13px;font-weight:700;color:#111827;border-bottom:1px solid #e5e7eb;'>${req.cargo_type}</td></tr><tr><td style='padding:8px 16px;font-size:13px;color:#6b7280;border-bottom:1px solid #e5e7eb;'>Weight</td><td style='padding:8px 16px;font-size:13px;font-weight:700;color:#111827;border-bottom:1px solid #e5e7eb;'>${req.weight_kg} kg</td></tr><tr><td style='padding:8px 16px;font-size:13px;color:#6b7280;border-bottom:1px solid #e5e7eb;'>Incoterms</td><td style='padding:8px 16px;font-size:13px;font-weight:700;color:#111827;border-bottom:1px solid #e5e7eb;'>${req.incoterms}</td></tr><tr><td style='padding:8px 16px;font-size:13px;color:#6b7280;'>Container</td><td style='padding:8px 16px;font-size:13px;font-weight:700;color:#111827;'>${req.container_type || 'TBD'}</td></tr>${req.is_hazardous ? '<tr><td colspan=2 style=padding:8px 16px;font-size:13px;color:#dc2626;font-weight:700;border-top:1px solid #e5e7eb;>Hazardous Cargo</td></tr>' : ''}</table><div style='background:#fef3c7;border:1px solid #fcd34d;border-radius:8px;padding:14px;'><p style='margin:0;font-size:13px;color:#92400e;'><strong>Reply to this email</strong> with your rate keeping <strong>${req.request_id}</strong> in subject. Include: price (USD), transit days, carrier, validity.</p></div></td></tr><tr><td style='background:#f8fafc;padding:18px 32px;text-align:center;border-top:1px solid #e2e8f0;'><p style='margin:0;font-size:11px;color:#94a3b8;'>CargoLink Platform &mdash; <a href='https://cargolink.sa' style='color:#64748b;text-decoration:none;'>cargolink.sa</a> &mdash; &copy; 2025 CargoLink</p></td></tr></table></td></tr></table></body></html>`;
  return { json: { forwarder_id: f.json.forwarder_id, forwarder_email: f.json.email, forwarder_company: f.json.company_name, request_id: req.request_id, user_name: req.user_name, user_email: req.user_email, email_subject: emailSubject, email_body: emailBody } };
});

const req = $('Code: Extract Request Data').first().json;
const sent = $('Gmail: Send to Forwarder').all();
return {
  json: {
    request_id: req.request_id,
    user_name: req.user_name,
    user_email: req.user_email,
    total_notified: sent.length
  }
};
